"use client";

import { useEffect, useState } from "react";
import { motion, useSpring, useMotionValue } from "framer-motion";

export default function CustomCursor() {
    const mouseX = useMotionValue(0);
    const mouseY = useMotionValue(0);

    const springConfig = { damping: 35, stiffness: 300, mass: 0.6 };
    const springX = useSpring(mouseX, springConfig);
    const springY = useSpring(mouseY, springConfig);

    const [isHovering, setIsHovering] = useState(false);
    const [hoverText, setHoverText] = useState("");

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            mouseX.set(e.clientX);
            mouseY.set(e.clientY);
        };

        const handleMouseOver = (e: MouseEvent) => {
            const target = e.target as HTMLElement;
            if (target.tagName === "BUTTON" || target.tagName === "A" || target.closest(".magnetic-item") || target.closest("button")) {
                setIsHovering(true);
                const text = target.innerText?.split('\n')[0] || "EXPLORE";
                setHoverText(`>> ${text.toUpperCase()}`);
            } else {
                setIsHovering(false);
                setHoverText("");
            }
        };

        window.addEventListener("mousemove", handleMouseMove);
        window.addEventListener("mouseover", handleMouseOver);

        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            window.removeEventListener("mouseover", handleMouseOver);
        };
    }, []);

    return (
        <div className="hidden md:block pointer-events-none fixed inset-0 z-[9999]">
            {/* Center Dot - Charcoal in Light Mode */}
            <motion.div
                className="absolute w-1.5 h-1.5 bg-[#333333] rounded-full shadow-[0_0_10px_rgba(0,0,0,0.1)]"
                style={{
                    x: springX,
                    y: springY,
                    translateX: "-50%",
                    translateY: "-50%",
                }}
                animate={{
                    scale: isHovering ? 2 : 1,
                    backgroundColor: isHovering ? "#5a7d9a" : "#333333",
                }}
            />

            {/* Technical Outer Frame - Light Mode */}
            <motion.div
                className="absolute w-12 h-12 border border-[#333333]/10 rounded-full"
                style={{
                    x: springX,
                    y: springY,
                    translateX: "-50%",
                    translateY: "-50%",
                }}
                animate={{
                    scale: isHovering ? 1.5 : 1,
                    borderColor: isHovering ? "rgba(90, 125, 154, 0.3)" : "rgba(51, 51, 51, 0.1)",
                    borderWidth: isHovering ? "2px" : "1px",
                }}
                transition={{ type: "spring", damping: 40, stiffness: 150 }}
            />

            {/* Data Label - Outfit Font */}
            <motion.div
                className="absolute text-[8px] font-black tracking-[0.3em] text-[#333333] whitespace-nowrap pt-2 luxury-text"
                style={{
                    x: springX,
                    y: springY,
                    translateX: "28px",
                    translateY: "12px",
                }}
                animate={{
                    opacity: isHovering ? 1 : 0,
                    x: isHovering ? 36 : 28,
                }}
            >
                {hoverText}
            </motion.div>

            {/* Corner Markers - Premium Detail */}
            {isHovering && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 0.3 }}
                    style={{
                        x: springX,
                        y: springY,
                        translateX: "-50%",
                        translateY: "-50%",
                    }}
                    className="absolute w-20 h-20"
                >
                    <div className="absolute top-0 left-0 w-3 h-[1px] bg-primary" />
                    <div className="absolute top-0 left-0 w-[1px] h-3 bg-primary" />
                    <div className="absolute bottom-0 right-0 w-3 h-[1px] bg-primary" />
                    <div className="absolute bottom-0 right-0 w-[1px] h-3 bg-primary" />
                </motion.div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";

interface Particle {
    id: number;
    x: number;
    y: number;
    color: string;
    type: "circle" | "square" | "ring";
}

export default function ExperimentalInteractions() {
    const [particles, setParticles] = useState<Particle[]>([]);
    const [mouseVelocity, setMouseVelocity] = useState(0);
    const lastMousePos = useRef({ x: 0, y: 0 });
    const lastTime = useRef(0);

    const colors = ["#5A7D9A", "#7FA7C4", "#333333", "#F2F2F2"];

    useEffect(() => {
        lastTime.current = Date.now();

        const handleKeyDown = (e: KeyboardEvent) => {
            // Prevent triggering on common shortcuts
            if (e.metaKey || e.ctrlKey) return;

            const id = Date.now();
            const x = Math.random() * window.innerWidth;
            const y = Math.random() * window.innerHeight;
            const color = colors[Math.floor(Math.random() * colors.length)];
            const types: Particle["type"][] = ["circle", "square", "ring"];
            const type = types[Math.floor(Math.random() * types.length)];

            setParticles((prev) => [...prev, { id, x, y, color, type }]);

            // Auto-remove particle after animation
            setTimeout(() => {
                setParticles((prev) => prev.filter((p) => p.id !== id));
            }, 1000);
        };

        const handleMouseMove = (e: MouseEvent) => {
            const now = Date.now();
            const dt = now - lastTime.current;
            if (dt === 0) return;

            const dx = e.clientX - lastMousePos.current.x;
            const dy = e.clientY - lastMousePos.current.y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            const velocity = dist / dt;

            setMouseVelocity((prev) => prev * 0.9 + velocity * 0.1);

            lastMousePos.current = { x: e.clientX, y: e.clientY };
            lastTime.current = now;
        };

        window.addEventListener("keydown", handleKeyDown);
        window.addEventListener("mousemove", handleMouseMove);

        return () => {
            window.removeEventListener("keydown", handleKeyDown);
            window.removeEventListener("mousemove", handleMouseMove);
        };
    }, []);

    return (
        <div className="fixed inset-0 pointer-events-none z-[80] overflow-hidden">
            {/* Patatap Inspired Keypress Visuals */}
            <AnimatePresence>
                {particles.map((p) => (
                    <motion.div
                        key={p.id}
                        initial={{ opacity: 0, scale: 0 }}
                        animate={{ opacity: 0.4, scale: 4 }}
                        exit={{ opacity: 0, scale: 8 }}
                        transition={{ duration: 0.8, ease: "easeOut" }}
                        className="absolute rounded-full"
                        style={{
                            left: p.x,
                            top: p.y,
                            width: 100,
                            height: 100,
                            marginLeft: -50,
                            marginTop: -50,
                            border: p.type === "ring" ? `2px solid ${p.color}` : "none",
                            backgroundColor: p.type !== "ring" ? p.color : "transparent",
                            borderRadius: p.type === "square" ? "0px" : "100%",
                        }}
                    />
                ))}
            </AnimatePresence>

            {/* Staggering Beauty Inspired Mouse Reaction (Global Overlay) */}
            <motion.div
                animate={{
                    opacity: Math.min(mouseVelocity * 0.2, 0.15),
                }}
                className="absolute inset-0 bg-primary mix-blend-soft-light transition-opacity duration-300 pointer-events-none"
            />

            {/* Velocity Based Vignette Distortion */}
            <motion.div
                animate={{
                    backdropFilter: `blur(${Math.min(mouseVelocity * 5, 10)}px)`,
                } as { backdropFilter: string }}
                className="absolute inset-0 pointer-events-none"
                style={{
                    maskImage: "radial-gradient(circle at center, transparent 30%, black 100%)",
                    WebkitMaskImage: "radial-gradient(circle at center, transparent 30%, black 100%)",
                }}
            />
        </div>
    );
}

